#!/usr/bin/env bash
# ============================================================================
# Post-Edit Formatter — v{{VERSION}}
# Event: PostToolUse | Matcher: Edit,Write
# Generated by {{PROJECT_NAME}} harness-marketplace plugin
# Reads JSON from stdin (Claude Code v2 hook format)
# Non-blocking: always exits 0 (formatter output goes to stderr)
# ============================================================================
set -uo pipefail

# shellcheck disable=SC1091
source "$(dirname "$0")/_parse.sh"

# ═══ GENERATED RULES (overwritten on upgrade) ═══

FILE_PATH="${TOOL_FILE_PATH:-}"

if [[ -z "$FILE_PATH" ]]; then
  exit 0
fi

# Normalize path separators
FILE_PATH="${FILE_PATH//\\//}"

# Only format known source/config files
case "$FILE_PATH" in
  *.ts|*.tsx|*.js|*.jsx|*.vue|*.svelte|*.css|*.scss|*.less|*.json|*.yaml|*.yml|*.md|*.html|*.py|*.rb|*.go|*.rs|*.graphql|*.gql)
    ;;
  *)
    exit 0
    ;;
esac

# Check if file exists
if [[ ! -f "$FILE_PATH" ]]; then
  exit 0
fi

FORMAT_CMD="{{FORMAT_COMMAND}}"

if [[ -z "$FORMAT_CMD" ]]; then
  exit 0
fi

# Replace common placeholders with the actual file path
if echo "$FORMAT_CMD" | grep -q '{file}'; then
  FORMAT_CMD="${FORMAT_CMD//\{file\}/"$FILE_PATH"}"
else
  # Append file path if no placeholder
  FORMAT_CMD="$FORMAT_CMD \"$FILE_PATH\""
fi

# Run formatter silently — only report on failure
FORMAT_OUTPUT=""
FORMAT_OUTPUT=$(eval "$FORMAT_CMD" 2>&1)
FORMAT_EXIT=$?

if [[ "$FORMAT_EXIT" -ne 0 ]]; then
  echo "[FORMAT] Formatter encountered an issue with '$(basename "$FILE_PATH")':" >&2
  echo "$FORMAT_OUTPUT" >&2
fi

# ═══ CUSTOM RULES BELOW (preserved on upgrade) ═══

# Add your own post-edit formatting rules here.
# They will be preserved when the plugin is upgraded.
#
# Example: Run a specific formatter for SQL files
#   case "$FILE_PATH" in
#     *.sql)
#       npx sql-formatter "$FILE_PATH" --write 2>/dev/null || true
#       ;;
#   esac

# Non-blocking: always exit 0
exit 0
